const src = $input.first().json;
const body = src.body || src;
const q     = (body.q    || '').toString().trim();
const arch  = (body.arch || '').toString().trim();
const limit = Math.min(Math.max(parseInt(body.limit ?? 50, 10) || 50, 1), 100);
return [{ json: { q, arch, limit } }];

const rows = $input.all().map(item => item.json);
const items = rows.map(r => {
  const raw = typeof r.raw === 'string' ? JSON.parse(r.raw) : (r.raw || {});
  return {
    id:          raw.id || ('bat_' + r.id),
    brand:       r.manufacturer,
    model:       r.model,
    chemistry:   r.chemistry,
    kwh:         r.nominal_kwh ? Number(r.nominal_kwh) : null,
    usableKwh:   r.usable_kwh  ? Number(r.usable_kwh)  : null,
    v:           r.voltage     ? Number(r.voltage)     : null,
    cycles:      r.cycles      ? Number(r.cycles)      : null,
    arch:        r.arch,
    dod:         raw.dod          ?? null,
    warrantyYears: raw.warrantyYears ?? null,
    kgPerModule: raw.kgPerModule   ?? null,
    source: 'Catálogo ALEBAS (Postgres)',
  };
});
return [{ json: { ok: true, items, total: items.length, syncedAt: new Date().toISOString() } }];
